161	        as: 'prodOrderDetail',
162	        foreignKey: 'prodOrderDetailPkey',
163	        targetKey: 'pkey'
164	      });
165	      models.itemHeader.belongsToMany(models.ProdOrderDetail, {
166	        as: 'linkedProdOrderDetails',
167	        through: models.item_prod_order_detail_associations,
168	        foreignKey: 'itemHeaderId',
169	        otherKey: 'prodOrderDetailPkey'
170	      });
171	      models.ProdOrderDetail.belongsToMany(models.itemHeader, {
172	        as: 'linkedItemHeaders',
173	        through: models.item_prod_order_detail_associations,
174	        foreignKey: 'prodOrderDetailPkey',
175	        otherKey: 'itemHeaderId'
