188	      if (data) {
189	        //if UDFElement_id_fk is 0 it means that we will run that on constructor
190	        //if UDFTable_primary_id is 0 and UDFTable_associate_type is 0 then that is the primary table for the associations
191	        data.forEach(element => {
192	          if (element.UDFTable_primary_id == '0') {
193	            primaryTables.push(element)
