204	              models[pkTablesElement.UDFTable_name][jointTables[i].UDFTable_associate_type](models[jointTables[i].UDFTable_name], { foreignKey: jointTables[i].UDFTable_foreignKey })
205	            }
206	          });
207	        };
208	      } else {
209	      }
210	    })
211	  return models
212	}
