42	async function startServer() {
43	  try {
44	    // Cache the LicenseFeedBacks for tracking utility mapping
45	    const feedbacks = await db.LicenseFeedBacks.findAll();
46	    globalThis.sql = globalThis.sql || {};
47	    globalThis.sql.LicenseFeedBacksCache = feedbacks;
48	    console.log(`Loaded ${feedbacks.length} LicenseFeedBacks into cache.`);
49	
50	    // Cache LicensingTime records for estimated date calculations in prod tracking
51	    const licensingTimes = await db.LicensingTime.findAll();
52	    globalThis.sql.LicensingTimeCache = licensingTimes.map(r => r.dataValues);
53	    console.log(`Loaded ${licensingTimes.length} LicensingTimes into cache.`);
54	
55	    // Pre-build mg_code → LicensingTime record map at startup.
56	    // For each mg_code we try every associated mg_desc (e.g. SE → "16X40\"", "SEGA", "SPELLS")
57	    // and keep the first one that fuzzy-matches a LicensingTime record.
58	    // This avoids repeated fuzzy matching on every request and handles codes with multiple descs.
59	    const { fuzzyMatchLicensor, fuzzyMatch } = require('./helpers/leadTimeUtils');
60	    const merchGroups = await db.merchGroup.findAll({ attributes: ['mg_code', 'mg_desc'] });
61	    const mgCodeDescs = {};
62	    for (const mg of merchGroups) {
63	      if (!mg.mg_code) continue;
64	      if (!mgCodeDescs[mg.mg_code]) mgCodeDescs[mg.mg_code] = [];
65	      if (mg.mg_desc && !mgCodeDescs[mg.mg_code].includes(mg.mg_desc)) {
66	        mgCodeDescs[mg.mg_code].push(mg.mg_desc);
67	      }
68	    }
69	
70	    // mg_code (licensor group 05) → LicensingTime record
71	    const licTimeCache = globalThis.sql.LicensingTimeCache;
72	    const mgLicTimesMap = {};
73	    for (const [code, descs] of Object.entries(mgCodeDescs)) {
74	      for (const desc of descs) {
75	        const match = fuzzyMatchLicensor(desc, licTimeCache);
76	        if (match) { mgLicTimesMap[code] = match; break; }
77	      }
78	    }
79	    globalThis.sql.MgLicTimesMap = mgLicTimesMap;
80	    console.log(`Built LicensingTime map for ${Object.keys(mgLicTimesMap).length} mg_codes.`);
81	
82	    // mg_code (product type group 01) → FactoryTime record
83	    // Used to calculate factory days for needed-date backwards calculation.
84	    const allFactory = await db.FactoryTime.findAll();
85	    const factoryCache = allFactory.map(r => r.dataValues);
86	    const mgFactoryTimesMap = {};
87	    for (const [code, descs] of Object.entries(mgCodeDescs)) {
88	      for (const desc of descs) {
89	        const match = fuzzyMatch(desc, factoryCache, 'product_subtype');
90	        if (match) { mgFactoryTimesMap[code] = match; break; }
91	      }
92	    }
93	    globalThis.sql.MgFactoryTimesMap = mgFactoryTimesMap;
94	    console.log(`Built FactoryTime map for ${Object.keys(mgFactoryTimesMap).length} mg_codes.`);
95	
96	    app.listen(port, function () {
97	      console.log(`🚀 License Tracking Server running on port ${port} in the ${env} environment`);
98	      console.log(`🌐 Web URL: ${process.env.WEB_URL}`);
99	      console.log(`🧠 API Address: ${process.env.API_ADDRESS}`);
100	      console.log(`📦 Schema: ${process.env.SCHEMA}`);
101	      console.log(`⚙️  Env File: ${envFile}`);
102	    });
103	  } catch (error) {
104	    console.error('Failed to initialize the application:', error);
105	    process.exit(1);
106	  }
107	}
